// cloudflare-worker.js
addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request));
});

async function handleRequest(request) {
  const url = new URL(request.url);
  if (url.pathname === '/public') {
    return await publicWorker(request);
  } else if (url.pathname.startsWith('/internal/')) {
    return await internalWorker(url.pathname, request);
  }
}

// Public-facing worker
async function publicWorker(request) {
  try {
    const response = await fetch('https://example.com/public', { method: 'POST', body: request.body });
    return new Response(response.body, response);
  } catch (error) {
    console.error(error);
    return new Response(null, { status: 500 });
  }
}

// Internal worker
async function internalWorker(pathname, request) {
  try {
    const binding = await getBinding('internal-worker');
    const internalRequest = new Request(request.url.replace('/public', pathname), request);
    const response = await binding.fetch(internalRequest);
    return new Response(response.body, response);
  } catch (error) {
    console.error(error);
    return new Response(null, { status: 500 });
  }
}

// Service Binding
async function getBinding(name) {
  try {
    const bindings = await context.bindings;
    const binding = bindings[name];
    if (!binding) {
      throw new Error(`Service binding '${name}' not found`);
    }
    return binding;
  } catch (error) {
    console.error(error);
    throw error;
  }
}